import{_ as a,o as s,c as t,a4 as n}from"./chunks/framework.BIesbIg_.js";const h=JSON.parse('{"title":"Token Savings Proof","description":"","frontmatter":{},"headers":[],"relativePath":"reference/token-savings-proof.md","filePath":"reference/token-savings-proof.md"}'),o={name:"reference/token-savings-proof.md"};function i(l,e,p,d,c,r){return s(),t("div",null,[...e[0]||(e[0]=[n(`<h1 id="token-savings-proof" tabindex="-1">Token Savings Proof <a class="header-anchor" href="#token-savings-proof" aria-label="Permalink to &quot;Token Savings Proof&quot;">​</a></h1><p>Mathematical proof that GCF&#39;s structural overhead is lower than both JSON and TOON for graph-structured data. All analysis uses byte length as a proxy for token count (validated: byte length correlates 0.97 with o200k_base token count for ASCII-dominant payloads).</p><h2 id="notation" tabindex="-1">Notation <a class="header-anchor" href="#notation" aria-label="Permalink to &quot;Notation&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Symbol</th><th>Definition</th></tr></thead><tbody><tr><td><code>n</code></td><td>Number of symbols (nodes) in payload</td></tr><tr><td><code>e</code></td><td>Number of edges in payload</td></tr><tr><td><code>q</code></td><td>Average qualified name length in bytes</td></tr><tr><td><code>k</code></td><td>Average kind string length in bytes (full form)</td></tr><tr><td><code>k&#39;</code></td><td>Average abbreviated kind length (GCF)</td></tr><tr><td><code>g</code></td><td>Number of distance groups</td></tr><tr><td><code>L(x)</code></td><td>Byte length of encoding <code>x</code></td></tr></tbody></table><h2 id="_1-symbol-encoding" tabindex="-1">1. Symbol encoding <a class="header-anchor" href="#_1-symbol-encoding" aria-label="Permalink to &quot;1. Symbol encoding&quot;">​</a></h2><h3 id="json-one-symbol" tabindex="-1">JSON (one symbol) <a class="header-anchor" href="#json-one-symbol" aria-label="Permalink to &quot;JSON (one symbol)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{&quot;qualified_name&quot;:&quot;&lt;q&gt;&quot;,&quot;kind&quot;:&quot;&lt;k&gt;&quot;,&quot;score&quot;:0.78,&quot;provenance&quot;:&quot;&lt;p&gt;&quot;,&quot;distance&quot;:0}</span></span></code></pre></div><p>Fixed overhead per symbol:</p><ul><li><code>{&quot;qualified_name&quot;:&quot;</code> (19) + <code>&quot;,&quot;kind&quot;:&quot;</code> (9) + <code>&quot;,&quot;score&quot;:</code> (9) + <code>,&quot;provenance&quot;:&quot;</code> (15) + <code>&quot;,&quot;distance&quot;:</code> (12) + <code>}</code> (1) = <strong>65 bytes</strong></li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>L_json(symbol) = 65 + q + k + len(score) + len(provenance)</span></span></code></pre></div><p>For a typical symbol (q=45, k=8, score=4, prov=12):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>L_json(symbol) = 65 + 45 + 8 + 4 + 12 = 134 bytes</span></span></code></pre></div><h3 id="gcf-one-symbol" tabindex="-1">GCF (one symbol) <a class="header-anchor" href="#gcf-one-symbol" aria-label="Permalink to &quot;GCF (one symbol)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@{id} {kind&#39;} {qname} {score} {provenance}</span></span></code></pre></div><p>Fixed overhead per symbol:</p><ul><li><code>@</code> (1) + space (1) + space (1) + space (1) + space (1) + newline (1) = <strong>6 bytes</strong> + id digits</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>L_gcf(symbol) = 6 + digits(id) + k&#39; + q + len(score) + len(provenance)</span></span></code></pre></div><p>For the same symbol (q=45, k&#39;=2 for &quot;fn&quot;, score=4, prov=12, id=1 digit):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>L_gcf(symbol) = 6 + 1 + 2 + 45 + 4 + 12 = 70 bytes</span></span></code></pre></div><h3 id="per-symbol-savings" tabindex="-1">Per-symbol savings <a class="header-anchor" href="#per-symbol-savings" aria-label="Permalink to &quot;Per-symbol savings&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Δ_symbol = L_json - L_gcf = 134 - 70 = 64 bytes (48% per symbol)</span></span></code></pre></div><p>The savings come from:</p><ul><li>Field name elimination: 65 - 6 = <strong>59 bytes</strong> of structural overhead removed</li><li>Kind abbreviation: k - k&#39; (avg 6 bytes saved per symbol)</li></ul><h3 id="scaling" tabindex="-1">Scaling <a class="header-anchor" href="#scaling" aria-label="Permalink to &quot;Scaling&quot;">​</a></h3><p>For <code>n</code> symbols:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Total_json(symbols) = n * L_json(symbol) + 2n (commas) + 14 (&quot;symbols&quot;:[...])</span></span>
<span class="line"><span>                    = n * 136 + 14</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Total_gcf(symbols)  = n * L_gcf(symbol) + g * 12 (group headers)</span></span>
<span class="line"><span>                    = n * 70 + g * 12</span></span></code></pre></div><p>For n=500, g=3:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Total_json = 500 * 136 + 14 = 68,014 bytes</span></span>
<span class="line"><span>Total_gcf  = 500 * 70 + 36  = 35,036 bytes</span></span>
<span class="line"><span>Savings: 48.5%</span></span></code></pre></div><h2 id="_2-edge-encoding" tabindex="-1">2. Edge encoding <a class="header-anchor" href="#_2-edge-encoding" aria-label="Permalink to &quot;2. Edge encoding&quot;">​</a></h2><h3 id="json-one-edge" tabindex="-1">JSON (one edge) <a class="header-anchor" href="#json-one-edge" aria-label="Permalink to &quot;JSON (one edge)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{&quot;source&quot;:&quot;&lt;q1&gt;&quot;,&quot;target&quot;:&quot;&lt;q2&gt;&quot;,&quot;edge_type&quot;:&quot;&lt;t&gt;&quot;}</span></span></code></pre></div><p>Fixed overhead:</p><ul><li><code>{&quot;source&quot;:&quot;</code> (11) + <code>&quot;,&quot;target&quot;:&quot;</code> (11) + <code>&quot;,&quot;edge_type&quot;:&quot;</code> (14) + <code>&quot;}</code> (2) = <strong>38 bytes</strong></li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>L_json(edge) = 38 + q1 + q2 + len(type)</span></span></code></pre></div><p>For typical edge (q1=45, q2=45, type=5):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>L_json(edge) = 38 + 45 + 45 + 5 = 133 bytes</span></span></code></pre></div><h3 id="gcf-one-edge" tabindex="-1">GCF (one edge) <a class="header-anchor" href="#gcf-one-edge" aria-label="Permalink to &quot;GCF (one edge)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@{tgt}&lt;@{src} {type}</span></span></code></pre></div><p>Fixed overhead:</p><ul><li><code>@</code> (1) + <code>&lt;@</code> (2) + space (1) + newline (1) = <strong>5 bytes</strong> + id digits</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>L_gcf(edge) = 5 + digits(tgt_id) + digits(src_id) + len(type)</span></span></code></pre></div><p>For the same edge (ids are 1-3 digits, type=5):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>L_gcf(edge) = 5 + 2 + 2 + 5 = 14 bytes</span></span></code></pre></div><h3 id="per-edge-savings" tabindex="-1">Per-edge savings <a class="header-anchor" href="#per-edge-savings" aria-label="Permalink to &quot;Per-edge savings&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Δ_edge = L_json - L_gcf = 133 - 14 = 119 bytes (89.5% per edge)</span></span></code></pre></div><p>This is GCF&#39;s largest structural advantage. JSON repeats the full qualified name of both source and target for every edge. GCF uses 2-3 digit local IDs.</p><h3 id="scaling-1" tabindex="-1">Scaling <a class="header-anchor" href="#scaling-1" aria-label="Permalink to &quot;Scaling&quot;">​</a></h3><p>For <code>e</code> edges:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Total_json(edges) = e * L_json(edge) + 2e (commas) + 10 (&quot;edges&quot;:[...])</span></span>
<span class="line"><span>                  = e * 135 + 10</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Total_gcf(edges)  = e * L_gcf(edge) + 9 (&quot;## edges\\n&quot;)</span></span>
<span class="line"><span>                  = e * 14 + 9</span></span></code></pre></div><p>For e=200:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Total_json = 200 * 135 + 10 = 27,010 bytes</span></span>
<span class="line"><span>Total_gcf  = 200 * 14 + 9   = 2,809 bytes</span></span>
<span class="line"><span>Savings: 89.6%</span></span></code></pre></div><h2 id="_3-distance-grouping" tabindex="-1">3. Distance grouping <a class="header-anchor" href="#_3-distance-grouping" aria-label="Permalink to &quot;3. Distance grouping&quot;">​</a></h2><h3 id="json" tabindex="-1">JSON <a class="header-anchor" href="#json" aria-label="Permalink to &quot;JSON&quot;">​</a></h3><p>Each symbol carries a <code>&quot;distance&quot;: N</code> field:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Per symbol: 12 bytes (&quot;distance&quot;:N) + comma</span></span></code></pre></div><p>For n=500: <strong>6,500 bytes</strong> of distance metadata.</p><h3 id="gcf" tabindex="-1">GCF <a class="header-anchor" href="#gcf" aria-label="Permalink to &quot;GCF&quot;">​</a></h3><p>Group headers replace per-symbol fields:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## targets\\n    = 11 bytes</span></span>
<span class="line"><span>## related\\n    = 11 bytes</span></span>
<span class="line"><span>## extended\\n   = 12 bytes</span></span></code></pre></div><p>For g=3 groups: <strong>34 bytes</strong> total.</p><h3 id="savings" tabindex="-1">Savings <a class="header-anchor" href="#savings" aria-label="Permalink to &quot;Savings&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Δ_grouping = 6,500 - 34 = 6,466 bytes</span></span></code></pre></div><p>One-time declarations replace n repetitions. Savings scale linearly with n.</p><h2 id="_4-header-overhead" tabindex="-1">4. Header overhead <a class="header-anchor" href="#_4-header-overhead" aria-label="Permalink to &quot;4. Header overhead&quot;">​</a></h2><h3 id="json-1" tabindex="-1">JSON <a class="header-anchor" href="#json-1" aria-label="Permalink to &quot;JSON&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{&quot;tool&quot;:&quot;context_for_task&quot;,&quot;tokens_used&quot;:1847,&quot;token_budget&quot;:5000,...}</span></span></code></pre></div><p>Typical header: ~120 bytes (field names + values + delimiters).</p><h3 id="gcf-1" tabindex="-1">GCF <a class="header-anchor" href="#gcf-1" aria-label="Permalink to &quot;GCF&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GCF tool=context_for_task budget=5000 tokens=1847 symbols=500 pack_root=a1b2c3\\n</span></span></code></pre></div><p>Typical header: ~80 bytes.</p><h3 id="savings-1" tabindex="-1">Savings <a class="header-anchor" href="#savings-1" aria-label="Permalink to &quot;Savings&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Δ_header = 120 - 80 = 40 bytes (fixed, does not scale)</span></span></code></pre></div><p>Header savings are negligible at scale. The payload body dominates.</p><h2 id="_5-total-model" tabindex="-1">5. Total model <a class="header-anchor" href="#_5-total-model" aria-label="Permalink to &quot;5. Total model&quot;">​</a></h2><p>Combining all components:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>L_json(payload) = L_json(header) + Total_json(symbols) + Total_json(edges)</span></span>
<span class="line"><span>                = 120 + (n * 136 + 14) + (e * 135 + 10)</span></span>
<span class="line"><span>                = 144 + 136n + 135e</span></span>
<span class="line"><span></span></span>
<span class="line"><span>L_gcf(payload)  = L_gcf(header) + Total_gcf(symbols) + Total_gcf(edges)</span></span>
<span class="line"><span>                = 80 + (n * 70 + g * 12) + (e * 14 + 9)</span></span>
<span class="line"><span>                = 89 + 70n + 12g + 14e</span></span></code></pre></div><h3 id="savings-formula" tabindex="-1">Savings formula <a class="header-anchor" href="#savings-formula" aria-label="Permalink to &quot;Savings formula&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Δ(n, e, g) = L_json - L_gcf</span></span>
<span class="line"><span>           = (144 + 136n + 135e) - (89 + 70n + 12g + 14e)</span></span>
<span class="line"><span>           = 55 + 66n + 121e - 12g</span></span></code></pre></div><p>Savings grow linearly with both symbol count and edge count. Edge savings dominate because Δ_edge (121 bytes) &gt; Δ_symbol (66 bytes).</p><h3 id="savings-percentage" tabindex="-1">Savings percentage <a class="header-anchor" href="#savings-percentage" aria-label="Permalink to &quot;Savings percentage&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Savings% = Δ / L_json = (55 + 66n + 121e - 12g) / (144 + 136n + 135e)</span></span></code></pre></div><p>For typical payloads (g &lt;&lt; n):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>lim(n,e→∞) Savings% ≈ (66n + 121e) / (136n + 135e)</span></span></code></pre></div><p>At the median ratio e/n = 0.4 (edges per symbol):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>≈ (66 + 121*0.4) / (136 + 135*0.4) = 114.4 / 190 = 60.2%</span></span></code></pre></div><p>At e/n = 1.0 (dense graphs):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>≈ (66 + 121) / (136 + 135) = 187 / 271 = 69.0%</span></span></code></pre></div><p>At e/n = 2.0 (very dense):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>≈ (66 + 242) / (136 + 270) = 308 / 406 = 75.9%</span></span></code></pre></div><p><strong>Conclusion:</strong> GCF savings range from 60% (sparse) to 76% (dense) asymptotically, increasing with edge density. The measured 84% includes kind abbreviation savings not fully captured in this simplified model.</p><h2 id="_6-gcf-vs-toon" tabindex="-1">6. GCF vs TOON <a class="header-anchor" href="#_6-gcf-vs-toon" aria-label="Permalink to &quot;6. GCF vs TOON&quot;">​</a></h2><p>TOON uses tabular encoding for uniform arrays. For symbol data:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>symbols[500]{qualified_name,kind,score,provenance,distance}:</span></span>
<span class="line"><span>  &lt;q&gt;,&lt;k&gt;,&lt;score&gt;,&lt;prov&gt;,&lt;dist&gt;</span></span>
<span class="line"><span>  &lt;q&gt;,&lt;k&gt;,&lt;score&gt;,&lt;prov&gt;,&lt;dist&gt;</span></span>
<span class="line"><span>  ...</span></span></code></pre></div><h3 id="toon-per-symbol-cost" tabindex="-1">TOON per-symbol cost <a class="header-anchor" href="#toon-per-symbol-cost" aria-label="Permalink to &quot;TOON per-symbol cost&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>L_toon(symbol) = q + 1 + k + 1 + len(score) + 1 + len(prov) + 1 + len(dist) + 1</span></span>
<span class="line"><span>               = q + k + len(score) + len(prov) + len(dist) + 5 (delimiters + newline)</span></span></code></pre></div><p>For typical symbol: 45 + 8 + 4 + 12 + 1 + 5 = <strong>75 bytes</strong></p><h3 id="gcf-per-symbol-cost-from-above-70-bytes" tabindex="-1">GCF per-symbol cost (from above): <strong>70 bytes</strong> <a class="header-anchor" href="#gcf-per-symbol-cost-from-above-70-bytes" aria-label="Permalink to &quot;GCF per-symbol cost (from above): **70 bytes**&quot;">​</a></h3><h3 id="per-symbol-advantage" tabindex="-1">Per-symbol advantage <a class="header-anchor" href="#per-symbol-advantage" aria-label="Permalink to &quot;Per-symbol advantage&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Δ_gcf_vs_toon(symbol) = 75 - 70 = 5 bytes per symbol</span></span></code></pre></div><p>Small per-symbol savings. The real advantage is in edges.</p><h3 id="toon-edge-encoding" tabindex="-1">TOON edge encoding <a class="header-anchor" href="#toon-edge-encoding" aria-label="Permalink to &quot;TOON edge encoding&quot;">​</a></h3><p>TOON has no special edge encoding. Edges are either:</p><ol><li>A separate tabular array (repeating full qualified names like JSON), or</li><li>Embedded in an object structure</li></ol><p>Best case (tabular edges):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>edges[200]{source,target,type}:</span></span>
<span class="line"><span>  &lt;q1&gt;,&lt;q2&gt;,&lt;type&gt;</span></span>
<span class="line"><span>  ...</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>L_toon(edge) = q1 + 1 + q2 + 1 + len(type) + 1 = q1 + q2 + len(type) + 3</span></span></code></pre></div><p>For typical: 45 + 45 + 5 + 3 = <strong>98 bytes</strong></p><h3 id="gcf-edge-cost-from-above-14-bytes" tabindex="-1">GCF edge cost (from above): <strong>14 bytes</strong> <a class="header-anchor" href="#gcf-edge-cost-from-above-14-bytes" aria-label="Permalink to &quot;GCF edge cost (from above): **14 bytes**&quot;">​</a></h3><h3 id="per-edge-advantage-over-toon" tabindex="-1">Per-edge advantage over TOON <a class="header-anchor" href="#per-edge-advantage-over-toon" aria-label="Permalink to &quot;Per-edge advantage over TOON&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Δ_gcf_vs_toon(edge) = 98 - 14 = 84 bytes per edge (85.7% savings)</span></span></code></pre></div><h3 id="total-gcf-vs-toon" tabindex="-1">Total GCF vs TOON <a class="header-anchor" href="#total-gcf-vs-toon" aria-label="Permalink to &quot;Total GCF vs TOON&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Δ_total(n, e) = 5n + 84e</span></span></code></pre></div><p>For n=500, e=200:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Δ = 5*500 + 84*200 = 2,500 + 16,800 = 19,300 bytes</span></span></code></pre></div><p>GCF is 19,300 bytes smaller than TOON for a 500-symbol, 200-edge payload. This aligns with the measured result: GCF 11,090 tokens vs TOON 16,378 tokens (32% smaller).</p><h3 id="why-edges-are-the-differentiator" tabindex="-1">Why edges are the differentiator <a class="header-anchor" href="#why-edges-are-the-differentiator" aria-label="Permalink to &quot;Why edges are the differentiator&quot;">​</a></h3><p>TOON was designed for generic tabular data. It has no concept of references between records. Every edge must spell out the full identifier of both source and target.</p><p>GCF&#39;s local ID system (<code>@0</code>, <code>@1</code>) means edges cost ~14 bytes regardless of identifier length. A symbol with a 120-character qualified name costs the same in an edge reference as one with a 10-character name.</p><p>This advantage grows with:</p><ul><li>Longer qualified names (common in Java/Go packages)</li><li>Higher edge density (call graphs, dependency graphs)</li><li>Larger payloads (more symbols = longer IDs but still 2-3 digits for &lt;1000 symbols)</li></ul><h2 id="_7-session-deduplication-model" tabindex="-1">7. Session deduplication model <a class="header-anchor" href="#_7-session-deduplication-model" aria-label="Permalink to &quot;7. Session deduplication model&quot;">​</a></h2><p>After call <code>c</code> with overlap ratio <code>r</code> (fraction of symbols seen before):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>L_session(call_c) = (1-r) * L_gcf(new_symbols) + r * L_bare_ref * n_total + L_gcf(edges)</span></span></code></pre></div><p>Where <code>L_bare_ref = digits(id) + 28</code> bytes (<code>@{id} # previously transmitted\\n</code>).</p><p>For r=0.8, n=50, e=20 (typical 3rd call):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>New symbols: 10 * 70 = 700 bytes</span></span>
<span class="line"><span>Bare refs: 40 * 30 = 1,200 bytes</span></span>
<span class="line"><span>Edges: 20 * 14 = 280 bytes</span></span>
<span class="line"><span>Total: 2,180 bytes</span></span>
<span class="line"><span></span></span>
<span class="line"><span>vs full GCF: 50 * 70 + 20 * 14 = 3,780 bytes</span></span>
<span class="line"><span>vs JSON: 50 * 136 + 20 * 135 = 9,500 bytes</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Session savings vs JSON: 77.1%</span></span></code></pre></div><h2 id="_8-empirical-validation" tabindex="-1">8. Empirical validation <a class="header-anchor" href="#_8-empirical-validation" aria-label="Permalink to &quot;8. Empirical validation&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Prediction</th><th>Measured</th><th>Error</th></tr></thead><tbody><tr><td>500-sym savings vs JSON</td><td>60-76% (model)</td><td>79% (measured)</td></tr><tr><td>500-sym savings vs TOON</td><td>~32% (model: 19,300 / (19,300 + L_gcf))</td><td>32% (measured)</td></tr><tr><td>Session savings (5th call)</td><td>~77-93% vs JSON (model)</td><td>92.7% (measured)</td></tr><tr><td>Edge savings</td><td>89.5% (model)</td><td>Not independently measured</td></tr></tbody></table><p>The model slightly underpredicts total savings because it uses average values and excludes second-order effects (kind abbreviation contributes ~1-2% additional savings, distance grouping eliminates array-level overhead).</p>`,129)])])}const u=a(o,[["render",i]]);export{h as __pageData,u as default};
